import express from "express";
import * as courseService from "./courseService.js";

export function startHealthServer({ serviceName, port, db }) {
  const app = express();
  app.use(express.json());

  // 1. Giữ nguyên API Healthcheck
  app.get("/health", async (req, res) => {
    try {
      await db.raw("select 1");
      res.json({
        status: "ok",
        service: serviceName,
      });
    } catch (error) {
      res.status(503).json({
        status: "error",
        service: serviceName,
      });
    }
  });

  // 2. Bổ sung REST API cho Courses (Để Postman và GraphQL có thể gọi)
  app.get("/courses", async (req, res) => {
    try {
      const limit = parseInt(req.query.limit) || 10;
      const offset = parseInt(req.query.offset) || 0;
      // Gọi xuống logic service. Tuỳ vào code của bạn mà truyền param cho đúng.
      const result = await courseService.listCourses({ limit, offset });
      res.json(result);
    } catch (error) {
      res.status(500).json({ error: error.message });
    }
  });

  app.get("/courses/:id", async (req, res) => {
    try {
      // Gọi service lấy chi tiết khoá học
      const result = await courseService.getCourse({ id: req.params.id }); 
      if (!result) {
        return res.status(404).json({ error: "Course not found" });
      }
      res.json(result);
    } catch (error) {
      res.status(500).json({ error: error.message });
    }
  });

  return app.listen(port, () => {
    console.log(`${serviceName} HTTP REST/Health endpoint listening on ${port}`);
  });
}